/* practice with Dukkha */
#include <stdio.h>

int main() {
	int n, e, o;

	scanf("%d", &n);
	if (n <= 5) {
		printf(n == 3 ? "0\n" : "1\n");
		return 0;
	}
	e = 4, o = 5;
	while (e < n && o < n) {
		int o_ = e + e + 1;
		int e_ = e + o + 1;

		e = e_, o = o_;
		if (e == n || o == n) {
			printf("1\n");
			return 0;
		}
	}
	printf("0\n");
	return 0;
}

