fn run() {
    input! {
        n: u64,
    }
    if n <= 2 {
        println!("1");
        return;
    }
    let mut m = 4;
    let mut d = 1;
    while m + 1 < n {
        m = 2 * (m + 1) - d;
        d ^= 1;
    }
    if m == n || m + 1 == n {
        println!("1");
    } else {
        println!("0");
    }
}

fn main() {
    run();
}
